"use client"

import { useState } from "react"
import { Download } from "lucide-react"
import { toast } from "sonner"
import { obtenerDatosExportacion } from "./actions"
import * as XLSX from "xlsx"

export function ExportOrdersButton() {
    const [isLoading, setIsLoading] = useState(false)

    const handleExport = async () => {
        setIsLoading(true)
        const toastId = toast.loading("Generando Excel de ventas...")

        try {
            const result = await obtenerDatosExportacion()

            if (result.error) {
                toast.error("Error al exportar", { id: toastId, description: result.error })
                return
            }

            if (result.rows && result.rows.length > 0) {
                // Crear workbook
                const wb = XLSX.utils.book_new()

                // Crear la hoja principal
                const ws = XLSX.utils.json_to_sheet(result.rows, {
                    header: ["pedido", "fecha", "hora", "cliente", "email", "tipo_entrega", "estado", "metodo_pago", "total"],
                })

                // Estilizar headers bonitos
                ws["!cols"] = [
                    { wch: 10 },  // pedido
                    { wch: 12 },  // fecha
                    { wch: 8 },   // hora
                    { wch: 25 },  // cliente
                    { wch: 30 },  // email
                    { wch: 14 },  // tipo_entrega
                    { wch: 18 },  // estado
                    { wch: 14 },  // metodo_pago
                    { wch: 12 },  // total
                ]

                // Renombrar headers
                const headerMap: Record<string, string> = {
                    pedido: "N┬░ Pedido",
                    fecha: "Fecha",
                    hora: "Hora",
                    cliente: "Cliente",
                    email: "Email",
                    tipo_entrega: "Tipo Entrega",
                    estado: "Estado",
                    metodo_pago: "M├®todo Pago",
                    total: "Total ($)",
                }
                const headerKeys = Object.keys(headerMap)
                headerKeys.forEach((key, i) => {
                    const cell = XLSX.utils.encode_cell({ r: 0, c: i })
                    if (ws[cell]) ws[cell].v = headerMap[key]
                })

                XLSX.utils.book_append_sheet(wb, ws, "Ventas")

                // Descargar
                const fechaArchivo = new Date().toISOString().split("T")[0]
                XLSX.writeFile(wb, `reporte_ventas_${fechaArchivo}.xlsx`)

                toast.success("┬íListo, cari├▒o! Excel descargado ­ƒôè", {
                    id: toastId,
                    description: `${result.rows.length} pedidos exportados.`,
                })
            }
        } catch (error) {
            toast.error("Ocurri├│ un error inesperado", { id: toastId })
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <button
            onClick={handleExport}
            disabled={isLoading}
            className="flex items-center gap-2 bg-admin-surface border border-white/10 text-gray-300 hover:text-white hover:border-white/20 font-semibold px-4 py-2 rounded-xl transition-all disabled:opacity-50 disabled:cursor-not-allowed text-sm"
        >
            <Download className={`w-4 h-4 ${isLoading ? 'animate-bounce' : ''}`} />
            {isLoading ? "Exportando..." : "Excel"}
        </button>
    )
}

"use client"

import { useState, useTransition } from "react"
import { actualizarEstadoPedido, type EstadoPedido } from "../actions"
import { toast } from "sonner"
import { Clock, ChefHat, Truck, CheckCircle2, MapPin, Phone } from "lucide-react"

interface PedidoCocina {
    id: string
    numero_pedido: number
    estado: string
    total: number
    tipo_entrega: string
    direccion_entrega: string | null
    hora_solicitada: string | null
    notas: string | null
    created_at: string
    cliente_nombre: string
    cliente_telefono: string | null
    items: { cantidad: number; nombre: string }[]
}

const COLUMNAS = [
    {
        estado: "confirmado",
        titulo: "­ƒôï Por Preparar",
        siguienteEstado: "en_preparacion" as EstadoPedido,
        btnLabel: "Empezar a Cocinar",
        btnIcon: ChefHat,
        headerBg: "bg-amber-500/10 border-amber-500/20",
        headerText: "text-amber-400",
        cardBg: "border-amber-500/10",
        dotColor: "bg-amber-400",
    },
    {
        estado: "en_preparacion",
        titulo: "­ƒöÑ En Preparaci├│n",
        siguienteEstado: "en_delivery" as EstadoPedido,
        btnLabel: "Listo pa' Despacho",
        btnIcon: Truck,
        headerBg: "bg-brand-500/10 border-brand-500/20",
        headerText: "text-brand-400",
        cardBg: "border-brand-500/10",
        dotColor: "bg-brand-500",
    },
    {
        estado: "en_delivery",
        titulo: "­ƒÜÇ Listos / En Camino",
        siguienteEstado: "entregado" as EstadoPedido,
        btnLabel: "Marcar Entregado",
        btnIcon: CheckCircle2,
        headerBg: "bg-emerald-500/10 border-emerald-500/20",
        headerText: "text-emerald-400",
        cardBg: "border-emerald-500/10",
        dotColor: "bg-emerald-400",
    },
]

export function CocinaBoard({ pedidos }: { pedidos: PedidoCocina[] }) {
    const [isPending, startTransition] = useTransition()

    const avanzarEstado = (pedidoId: string, numeroPedido: number, nuevoEstado: EstadoPedido, label: string) => {
        startTransition(async () => {
            const result = await actualizarEstadoPedido(pedidoId, nuevoEstado)
            if (result?.error) {
                toast.error("Error", { description: result.error })
            } else {
                toast.success(`#${String(numeroPedido).padStart(5, "0")} ÔåÆ ${label}`)
            }
        })
    }

    return (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-6">
            {COLUMNAS.map((col) => {
                const pedidosCol = pedidos.filter(p => p.estado === col.estado)
                const BtnIcon = col.btnIcon

                return (
                    <div key={col.estado} className="space-y-3">
                        {/* Header de columna */}
                        <div className={`rounded-2xl border p-4 ${col.headerBg}`}>
                            <div className="flex items-center justify-between">
                                <h2 className={`font-heading font-bold text-sm ${col.headerText}`}>{col.titulo}</h2>
                                <span className={`w-6 h-6 rounded-full ${col.headerBg.split(" ")[0]} flex items-center justify-center text-xs font-black ${col.headerText}`}>
                                    {pedidosCol.length}
                                </span>
                            </div>
                        </div>

                        {/* Columna vac├¡a */}
                        {pedidosCol.length === 0 && (
                            <div className="bg-admin-surface rounded-2xl border border-white/5 p-8 text-center">
                                <p className="text-gray-500 text-sm font-medium">Sin pedidos aqu├¡</p>
                            </div>
                        )}

                        {/* Tarjetas */}
                        {pedidosCol.map((pedido) => (
                            <div
                                key={pedido.id}
                                className={`bg-admin-surface rounded-2xl border ${col.cardBg} p-4 space-y-3 transition-all hover:border-white/20`}
                            >
                                {/* Encabezado */}
                                <div className="flex items-start justify-between">
                                    <div>
                                        <div className="flex items-center gap-2">
                                            <span className={`w-2 h-2 rounded-full ${col.dotColor} animate-pulse`} />
                                            <span className="font-heading font-bold text-white text-sm">
                                                #{String(pedido.numero_pedido).padStart(5, "0")}
                                            </span>
                                        </div>
                                        <p className="text-xs text-gray-400 mt-0.5">{pedido.cliente_nombre}</p>
                                    </div>
                                    <div className="text-right">
                                        {pedido.hora_solicitada && (
                                            <span className="flex items-center gap-1 text-xs font-bold text-brand-400 bg-brand-500/10 px-2 py-0.5 rounded-full border border-brand-500/20">
                                                <Clock className="w-3 h-3" /> {pedido.hora_solicitada}
                                            </span>
                                        )}
                                        <span className="block text-xs text-gray-500 mt-1">
                                            {pedido.tipo_entrega === "delivery" ? "­ƒøÁ Delivery" : "­ƒÅ¬ Retiro"}
                                        </span>
                                    </div>
                                </div>

                                {/* Items */}
                                <ul className="space-y-1 bg-white/5 rounded-xl p-3">
                                    {pedido.items.map((item, i) => (
                                        <li key={i} className="text-sm text-gray-300 flex items-center gap-2">
                                            <span className="font-bold text-white text-xs bg-white/10 w-5 h-5 rounded flex items-center justify-center shrink-0">
                                                {item.cantidad}
                                            </span>
                                            <span className="truncate">{item.nombre}</span>
                                        </li>
                                    ))}
                                </ul>

                                {/* Notas */}
                                {pedido.notas && (
                                    <div className="text-xs text-amber-300/80 bg-amber-500/10 p-2 rounded-lg border border-amber-500/10">
                                        ­ƒÆ¼ {pedido.notas}
                                    </div>
                                )}

                                {/* Direcci├│n delivery */}
                                {pedido.tipo_entrega === "delivery" && pedido.direccion_entrega && (
                                    <div className="text-xs text-gray-400 flex items-start gap-1.5">
                                        <MapPin className="w-3.5 h-3.5 text-gray-500 shrink-0 mt-0.5" />
                                        <span>{pedido.direccion_entrega}</span>
                                    </div>
                                )}

                                {/* Contacto WA */}
                                {pedido.cliente_telefono && (
                                    <a
                                        href={`https://wa.me/${pedido.cliente_telefono.replace('+', '')}?text=${encodeURIComponent(`┬íHola ${pedido.cliente_nombre}! ­ƒæ®ÔÇì­ƒì│ Soy la T├¡a Elvira, te escribo por tu pedido #${String(pedido.numero_pedido).padStart(5, "0")}.`)}`}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="flex items-center gap-1.5 text-xs font-bold text-green-400 hover:text-green-300 transition-colors"
                                    >
                                        <Phone className="w-3 h-3" /> WhatsApp
                                    </a>
                                )}

                                {/* Bot├│n avanzar */}
                                <button
                                    onClick={() => avanzarEstado(pedido.id, pedido.numero_pedido, col.siguienteEstado, col.btnLabel)}
                                    disabled={isPending}
                                    className={`w-full flex items-center justify-center gap-2 font-bold text-sm py-2.5 rounded-xl transition-all disabled:opacity-50 ${col.headerBg} ${col.headerText} hover:opacity-80`}
                                >
                                    <BtnIcon className="w-4 h-4" />
                                    {isPending ? "Actualizando..." : col.btnLabel}
                                </button>
                            </div>
                        ))}
                    </div>
                )
            })}
        </div>
    )
}

"use client"

import { useState, useTransition } from "react"
import { Plus, Edit2, Trash2, Power, Check, X, Eye, EyeOff, Ban } from "lucide-react"
import { toggleItemActivo, eliminarItemMenu, guardarItemMenu } from "./actions"
import { toast } from "sonner"
import { Button } from "@/components/ui/Button"

// Tipos basados en nuestra BD
type Categoria = { id: string; nombre: string }
type ItemMenu = {
    id: string
    nombre: string
    descripcion: string | null
    precio: number
    imagen_url: string | null
    categoria_id: string
    activo: boolean
    stock: number | null
    agotado_manual: boolean
}

interface MenuManagerProps {
    items: ItemMenu[]
    categorias: Categoria[]
}

export function MenuManager({ items, categorias }: MenuManagerProps) {
    const [isPending, startTransition] = useTransition()

    // Editar / Modal
    const [modalOpen, setModalOpen] = useState(false)
    const [itemEditar, setItemEditar] = useState<ItemMenu | null>(null)

    // Filtro
    const [catSeleccionada, setCatSeleccionada] = useState<string>("todas")
    const [mostrarOcultos, setMostrarOcultos] = useState(false)

    // Manejo de estado Agotado Manual
    const handleToggleManual = (id: string, agotadoAcual: boolean) => {
        startTransition(async () => {
            const formData = new FormData()
            formData.append('id', id)
            formData.append('toggle_agotado', 'true')
            formData.append('agotado_manual', String(!agotadoAcual))

            const res = await guardarItemMenu(formData)
            if (res?.error) toast.error("Error", { description: res.error })
            else toast.success(`Item ${!agotadoAcual ? "marcado como agotado" : "reactivado de agotado"}`)
        })
    }

    // Manejo de Visibilidad
    const handleToggleVisibilidad = (id: string, activoActual: boolean) => {
        startTransition(async () => {
            const res = await toggleItemActivo(id, !activoActual)
            if (res?.error) toast.error("Error al cambiar visibilidad", { description: res.error })
            else toast.success(`Item ${activoActual ? "oculto" : "visible"} en el cat├ílogo`)
        })
    }

    // Manejo Lote
    const handleToggleTodos = (activo: boolean) => {
        if (!confirm(`┬┐Est├ís seguro de ${activo ? 'habilitar' : 'ocultar'} TODO el men├║ al p├║blico?`)) return
        startTransition(async () => {
            const formData = new FormData()
            formData.append('toggle_todos', 'true')
            formData.append('activo_masivo', String(activo))

            const res = await guardarItemMenu(formData)
            if (res?.error) toast.error("Error", { description: res.error })
            else toast.success(`Todo el men├║ ha sido ${activo ? "habilitado" : "ocultado"} exitosamente`)
        })
    }

    // Eliminar
    const handleEliminar = (id: string) => {
        if (!confirm("┬┐Seguro que deseas eliminar este ├¡tem permanentemente? Si ya tiene pedidos hist├│ricos, dar├í error.")) return

        startTransition(async () => {
            const res = await eliminarItemMenu(id)
            if (res?.error) toast.error("No se pudo eliminar", { description: res.error })
            else toast.success("├ìtem eliminado correctamente")
        })
    }

    // Guardar (Crear/Editar) v├¡a Form Action
    const handleSubmit = (formData: FormData) => {
        startTransition(async () => {
            const res = await guardarItemMenu(formData)
            if (res?.error) {
                toast.error("Error al guardar", { description: res.error })
            } else {
                toast.success(itemEditar ? "├ìtem actualizado" : "Nuevo ├¡tem creado")
                setModalOpen(false)
                setItemEditar(null)
            }
        })
    }

    const itemsFiltrados = items.filter(i => {
        if (catSeleccionada !== "todas" && i.categoria_id !== catSeleccionada) return false
        if (!mostrarOcultos && !i.activo) return false
        return true
    })

    return (
        <div className="space-y-6">
            {/* Barra de Controles Glogal */}
            <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between bg-white p-4 sm:p-5 rounded-2xl shadow-sm border border-gray-100">
                <div className="flex gap-2">
                    <Button
                        variant="primary"
                        onClick={() => { setItemEditar(null); setModalOpen(true); }}
                        className="px-5 py-2.5 shadow-md shadow-brand-500/20"
                    >
                        <Plus className="w-4 h-4 mr-2" /> A├▒adir Plato
                    </Button>
                </div>

                <div className="flex items-center gap-2 mt-2 sm:mt-0 w-full sm:w-auto overflow-x-auto scrollbar-hide pb-2 sm:pb-0">
                    <span className="text-xs font-bold text-gray-400 uppercase tracking-wider mr-2 hidden sm:inline-block">Acciones Masivas:</span>
                    <button
                        onClick={() => handleToggleTodos(true)}
                        disabled={isPending}
                        className="flex items-center gap-1.5 px-3 py-2 bg-emerald-50 text-emerald-600 hover:bg-emerald-100 rounded-lg text-sm font-semibold transition-colors disabled:opacity-50 whitespace-nowrap"
                        title="Hacer visibles todos los platos del cat├ílogo"
                    >
                        <Eye className="w-4 h-4" /> Mostrar Todos
                    </button>
                    <button
                        onClick={() => handleToggleTodos(false)}
                        disabled={isPending}
                        className="flex items-center gap-1.5 px-3 py-2 bg-gray-100 text-gray-600 hover:bg-gray-200 rounded-lg text-sm font-semibold transition-colors disabled:opacity-50 whitespace-nowrap"
                        title="Ocultar todo el cat├ílogo"
                    >
                        <EyeOff className="w-4 h-4" /> Ocultar Todos
                    </button>
                    <div className="w-px h-6 bg-gray-200 mx-1 hidden sm:block"></div>
                    <label className="flex items-center gap-2 text-sm font-semibold text-gray-600 bg-gray-50 px-3 py-2 rounded-lg cursor-pointer hover:bg-gray-100 transition-colors whitespace-nowrap border border-gray-100 mb-1 sm:mb-0">
                        <input type="checkbox" checked={mostrarOcultos} onChange={(e) => setMostrarOcultos(e.target.checked)} className="w-4 h-4 text-brand-500 rounded focus:ring-brand-500 bg-white" />
                        Ver Ocultos
                    </label>
                </div>
            </div>

            {/* Selector de Categor├¡as */}
            <div className="flex gap-2 overflow-x-auto w-full scrollbar-hide snap-x snap-mandatory pb-2">
                <button
                    onClick={() => setCatSeleccionada("todas")}
                    className={`snap-start px-4 py-2 rounded-xl text-sm font-semibold whitespace-nowrap transition-colors ${catSeleccionada === "todas" ? "bg-brand-500 text-white" : "bg-white text-gray-600 hover:bg-gray-50 border border-gray-200 shadow-sm"}`}
                >
                    Todos
                </button>
                {categorias.map(c => (
                    <button
                        key={c.id}
                        onClick={() => setCatSeleccionada(c.id)}
                        className={`snap-start px-4 py-2 rounded-xl text-sm font-semibold whitespace-nowrap transition-colors ${catSeleccionada === c.id ? "bg-brand-500 text-white" : "bg-white text-gray-600 hover:bg-gray-50 border border-gray-200 shadow-sm"}`}
                    >
                        {c.nombre}
                    </button>
                ))}
            </div>

            {/* Vista M├│vil: Tarjetas (Solo visible en pantallas chicas) */}
            <div className="flex flex-col gap-4 md:hidden">
                {itemsFiltrados.length === 0 ? (
                    <div className="bg-white rounded-2xl p-8 text-center text-gray-400 shadow-sm border border-gray-100">
                        No hay platos en esta categor├¡a.
                    </div>
                ) : (
                    itemsFiltrados.map(item => (
                        <div key={item.id} className={`bg-white rounded-2xl shadow-sm border border-gray-100 p-4 transition-all ${!item.activo ? "opacity-75 bg-gray-50" : ""}`}>
                            <div className="flex items-start gap-4 mb-4">
                                {item.imagen_url ? (
                                    <img src={item.imagen_url} alt={item.nombre} className="w-16 h-16 rounded-xl object-cover border border-gray-100 bg-gray-100 flex-shrink-0" />
                                ) : (
                                    <div className="w-16 h-16 rounded-xl bg-gray-100 flex items-center justify-center font-bold text-gray-400 text-[10px] text-center flex-shrink-0">Sin<br />Foto</div>
                                )}
                                <div className="flex-1 min-w-0">
                                    <h3 className="font-bold text-gray-900 text-lg leading-tight truncate">{item.nombre}</h3>
                                    {item.descripcion && (
                                        <p className="text-xs text-gray-500 line-clamp-2 mt-0.5 mb-1">{item.descripcion}</p>
                                    )}
                                    <p className="text-brand-600 font-bold mt-1">${item.precio.toLocaleString("es-CL")}</p>
                                </div>
                            </div>

                            <div className="flex items-center gap-2 mb-4 flex-wrap">
                                <span className="bg-gray-100 text-gray-600 px-2.5 py-1 rounded-md text-xs font-bold">
                                    Stock: {item.stock !== null ? item.stock : "Ôê×"}
                                </span>
                                {!item.activo ? (
                                    <span className="inline-flex items-center gap-1 px-2.5 py-1 bg-gray-100 text-gray-500 border border-gray-200 rounded-md text-xs font-bold">
                                        <EyeOff className="w-3 h-3" /> Oculto
                                    </span>
                                ) : item.agotado_manual ? (
                                    <span className="inline-flex items-center gap-1 px-2.5 py-1 bg-red-50 text-red-600 border border-red-200 rounded-md text-xs font-bold">
                                        <Ban className="w-3 h-3" /> Agotado (Manual)
                                    </span>
                                ) : item.stock === 0 ? (
                                    <span className="inline-flex items-center gap-1 px-2.5 py-1 bg-red-50 text-red-600 border border-red-200 rounded-md text-xs font-bold">
                                        <Ban className="w-3 h-3" /> Sin Stock
                                    </span>
                                ) : (
                                    <span className="inline-flex items-center gap-1 px-2.5 py-1 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-md text-xs font-bold">
                                        <Check className="w-3 h-3" /> Disponible
                                    </span>
                                )}
                            </div>

                            <div className="grid grid-cols-3 gap-2">
                                <button
                                    onClick={() => handleToggleVisibilidad(item.id, item.activo)}
                                    disabled={isPending}
                                    className={`flex justify-center items-center py-2.5 rounded-xl text-sm font-semibold transition-colors border ${item.activo ? "bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100" : "bg-emerald-50 text-emerald-700 border-emerald-200 hover:bg-emerald-100"}`}
                                >
                                    {item.activo ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </button>
                                <button
                                    onClick={() => { setItemEditar(item); setModalOpen(true) }}
                                    className="flex justify-center items-center py-2.5 bg-brand-50 text-brand-700 border border-brand-200 hover:bg-brand-100 rounded-xl text-sm font-semibold transition-colors"
                                >
                                    <Edit2 className="w-4 h-4" />
                                </button>
                                <button
                                    onClick={() => handleEliminar(item.id)}
                                    disabled={isPending}
                                    className="flex justify-center items-center py-2.5 bg-red-50 text-red-600 border border-red-200 hover:bg-red-100 rounded-xl text-sm font-semibold transition-colors h-[42px]"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>

            {/* Vista Desktop: Tabla (Oculta en m├│viles) */}
            <div className="hidden md:block bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-sm">
                        <thead>
                            <tr className="bg-gray-50 border-b border-gray-100 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">
                                <th className="px-5 py-4">Plato</th>
                                <th className="px-5 py-4">Precio</th>
                                <th className="px-5 py-4">Stock</th>
                                <th className="px-5 py-4">Disponibilidad</th>
                                <th className="px-5 py-4 text-right">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                            {itemsFiltrados.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="px-5 py-12 text-center text-gray-400">
                                        No hay platos en esta categor├¡a.
                                    </td>
                                </tr>
                            ) : (
                                itemsFiltrados.map(item => (
                                    <tr key={item.id} className={`hover:bg-gray-50 transition-colors ${!item.activo ? "opacity-60 bg-gray-50/50" : ""}`}>
                                        <td className="px-5 py-4">
                                            <div className="flex items-center gap-4">
                                                {item.imagen_url ? (
                                                    <img src={item.imagen_url} alt={item.nombre} className="w-12 h-12 rounded-xl object-cover border border-gray-100 bg-gray-100" />
                                                ) : (
                                                    <div className="w-12 h-12 rounded-xl bg-gray-100 flex items-center justify-center font-bold text-gray-400 text-xs">Sin Foto</div>
                                                )}
                                                <div>
                                                    <p className="font-bold text-gray-900">{item.nombre}</p>
