"use server"

import { createClient } from "@/lib/supabase/server"
import { revalidatePath } from "next/cache"

export async function toggleItemActivo(id: string, activo: boolean) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return { error: "No autorizado" }

    const { data: profile } = await supabase.from("profiles").select("rol").eq("id", user.id).single()
    if (profile?.rol !== "admin") return { error: "Sin permisos" }

    const { error } = await supabase.from("items_menu").update({ activo }).eq("id", id)
    if (error) return { error: error.message }

    revalidatePath("/admin/menu")
    revalidatePath("/")
    return { success: true }
}

export async function guardarItemMenu(formData: FormData) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return { error: "No autorizado" }

    const { data: profile } = await supabase.from("profiles").select("rol").eq("id", user.id).single()
    if (profile?.rol !== "admin") return { error: "Sin permisos" }

    // 1. Verificar si es una Acci├│n por Lote (Prioridad Absoluta)
    const isToggleTodos = formData.get("toggle_todos") === "true"
    if (isToggleTodos) {
        const activoMasivo = formData.get("activo_masivo") === "true"
        // Actualiza todos los registros y salta todas las dem├ís validaciones
        const { error: batchError } = await supabase.from('items_menu').update({ activo: activoMasivo }).not('id', 'is', null)
        if (batchError) return { error: batchError.message }
        revalidatePath("/admin/menu")
        revalidatePath("/")
        return { success: true }
    }

    const id = formData.get("id") as string | null

    // 2. Si es un toggle r├ípido de Agotado Manual desde la tabla
    const isToggleAgotado = formData.get("toggle_agotado") === 'true'
    if (isToggleAgotado && id) {
        const agotado_manual = formData.get("agotado_manual") === 'true'
        const { error } = await supabase.from("items_menu").update({ agotado_manual }).eq("id", id)
        if (error) return { error: error.message }
        revalidatePath("/admin/menu")
        revalidatePath("/")
        return { success: true }
    }

    // 3. Si llega hasta aqu├¡, se asume Creaci├│n o Edici├│n de un ├¡tem individual
    const nombre = formData.get("nombre") as string
    const descripcion = formData.get("descripcion") as string
    const precio = parseInt(formData.get("precio") as string)
    const categoria_id = formData.get("categoria_id") as string
    const stockRaw = formData.get("stock") as string | null
    const stock = stockRaw && stockRaw !== '' ? parseInt(stockRaw) : null
    const activo = formData.get("activo") === 'on'
    const agotado_manual = formData.get("agotado_manual") === 'on'
    const file = formData.get("imagen") as File | null

    if (!nombre || !precio || !categoria_id) {
        return { error: "Faltan campos obligatorios" }
    }

    let imagen_url = formData.get("imagen_url") as string | null

    // Subir imagen si se selecciona una nueva
    if (file && file.size > 0) {
        const fileExt = file.name.split('.').pop()
        const fileName = `${Math.random().toString(36).substring(2, 15)}_${Date.now()}.${fileExt}`
        const filePath = `platos/${fileName}`

        const { error: uploadError } = await supabase.storage
            .from("menu")
            .upload(filePath, file)

        if (uploadError) return { error: "Error al subir la imagen: " + uploadError.message }

        const { data: publicUrlData } = supabase.storage.from("menu").getPublicUrl(filePath)
        imagen_url = publicUrlData.publicUrl
    }

    const payload = {
        nombre,
        descripcion,
        precio,
        categoria_id,
        stock,
        activo,
        agotado_manual,
        ...(imagen_url && { imagen_url }),
    }

    let error;
    if (id) {
        const res = await supabase.from("items_menu").update(payload).eq("id", id)
        error = res.error
    } else {
        const res = await supabase.from("items_menu").insert([payload])
        error = res.error
    }

    if (error) return { error: error.message }

    revalidatePath("/admin/menu")
    revalidatePath("/")
    return { success: true }
}

export async function eliminarItemMenu(id: string) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return { error: "No autorizado" }

    const { data: profile } = await supabase.from("profiles").select("rol").eq("id", user.id).single()
    if (profile?.rol !== "admin") return { error: "Sin permisos" }

    // Verificar si est├í en alg├║n pedido
    const { data: enPedido } = await supabase.from("detalle_pedidos").select("id").eq("item_id", id).limit(1)

    if (enPedido && enPedido.length > 0) {
        return { error: "No se puede eliminar porque este plato ya est├í en pedidos hist├│ricos. Te sugerimos desactivarlo (Agotado)." }
    }

    const { error } = await supabase.from("items_menu").delete().eq("id", id)
    if (error) return { error: error.message }

    revalidatePath("/admin/menu")
    revalidatePath("/")
    return { success: true }
}

export async function guardarCategoria(formData: FormData) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return { error: "No autorizado" }

    const { data: profile } = await supabase.from("profiles").select("rol").eq("id", user.id).single()
    if (profile?.rol !== "admin") return { error: "Sin permisos" }

    const id = formData.get("id") as string | null
    const nombre = formData.get("nombre") as string
    const orden = formData.get("orden") ? parseInt(formData.get("orden") as string) : null

    if (!nombre) return { error: "El nombre es obligatorio" }

    const payload: any = { nombre }
    if (orden) payload.orden = orden

    let error;
    if (id) {
        const res = await supabase.from("categorias").update(payload).eq("id", id)
        error = res.error
    } else {
        const res = await supabase.from("categorias").insert([payload])
        error = res.error
    }

    if (error) return { error: error.message }

    revalidatePath("/admin/menu")
    revalidatePath("/admin/menu/categorias")
    revalidatePath("/")
    return { success: true }
}

export async function eliminarCategoria(id: string) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return { error: "No autorizado" }

    const { data: profile } = await supabase.from("profiles").select("rol").eq("id", user.id).single()
    if (profile?.rol !== "admin") return { error: "Sin permisos" }

    // Verificar si hay items usando esta categor├¡a
    const { data: itemsRef } = await supabase.from("items_menu").select("id").eq("categoria_id", id).limit(1)

    if (itemsRef && itemsRef.length > 0) {
        return { error: "No se puede eliminar porque hay platos asignados a esta categor├¡a. Mueve los platos a otra categor├¡a primero." }
    }

    const { error } = await supabase.from("categorias").delete().eq("id", id)
    if (error) return { error: error.message }

    revalidatePath("/admin/menu")
    revalidatePath("/admin/menu/categorias")
    revalidatePath("/")
    return { success: true }
}

"use server"

import { createClient } from "@/lib/supabase/server"
import { revalidatePath } from "next/cache"
import fs from "fs/promises"
import path from "path"

export async function prepararMenuManana() {
    try {
        const supabase = await createClient()

        // 1. Verificaci├│n de Seguridad (Solo Admin)
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) return { error: "No autorizado" }
        const { data: profile } = await supabase.from("profiles").select("rol").eq("id", user.id).single()
        if (profile?.rol !== "admin") return { error: "Sin permisos" }

        // 2. Ocultar TODO el men├║ actual
        const { error: hideError } = await supabase.from('items_menu').update({ activo: false }).not('id', 'is', null)
        if (hideError) throw new Error("Error al ocultar men├║ actual: " + hideError.message)

        // 3. Obtener las Categor├¡as para asignar correctamente (Buscamos por nombre aproximado)
        const { data: categorias } = await supabase.from("categorias_menu").select("*")
        const getCatId = (keywords: string[]) => {
            const cat = categorias?.find(c => keywords.some(k => c.nombre.toLowerCase().includes(k)))
            return cat ? cat.id : categorias?.[0]?.id // Fallback preventivo
        }

        const catPlatos = getCatId(["fondo", "plato"])
        const catEnsaladas = getCatId(["ensalada"])
        const catPostres = getCatId(["postre"])

        // Definici├│n de Platos M├ígicos
        const nuevosPlatos = [
            {
                nombre: "Carbonada",
                precio: 3500,
                descripcion: "Exquisita carbonada casera chilena.",
                categoria_id: catPlatos,
                archivo_local: "Carbonada.jpeg"
            },
            {
                nombre: "Ensalada con At├║n y Huevo",
                precio: 3500,
                descripcion: "Ensalada fresca de mix de lechugas, at├║n y huevo duro.",
                categoria_id: catEnsaladas,
                archivo_local: "Ensalada Mixta de Huevo y At├║n.jpeg"
            },
            {
                nombre: "Fruta con Yogurt y Granola",
                precio: 2500,
                descripcion: "Postre fresco de fruta picada, yogurt natural y granola crujiente.",
                categoria_id: catPostres,
                archivo_local: null // No tenemos por ahora
            }
        ]

        // Variables maestras de ruta
        // Usa la ruta absoluta desde el punto de vista del usuario
        const imageDir = path.join("C:", "Users", "mwarr", "OneDrive - UNIVERSIDAD DE LAS AMERICAS", "NOTEBOOK", "PROYECTOS", "Mi Colaci├│n", "Platos")

        // 4. Procesar e Insertar/Actualizar
        for (const plato of nuevosPlatos) {
            let imagen_url = null

            // Subir imagen si se especific├│ el archivo local
            if (plato.archivo_local) {
                const filePathLocal = path.join(imageDir, plato.archivo_local)

                try {
                    const imageBuffer = await fs.readFile(filePathLocal)
                    const fileExt = plato.archivo_local.split('.').pop()
                    const fileName = `${plato.nombre.replace(/\s+/g, '_').toLowerCase()}_${Date.now()}.${fileExt}`
                    const filePathCloud = `platos_diarios/${fileName}`

                    const { error: uploadError } = await supabase.storage
                        .from("menu")
                        .upload(filePathCloud, imageBuffer, { contentType: 'image/jpeg' })

                    if (uploadError) {
                        console.error("No se pudo subir la imagen", plato.archivo_local, uploadError)
                    } else {
                        const { data: publicUrlData } = supabase.storage.from("menu").getPublicUrl(filePathCloud)
                        imagen_url = publicUrlData.publicUrl
                    }
                } catch (imgLocalErr) {
                    console.error("No se encontr├│ la imagen local:", filePathLocal, imgLocalErr)
                }
            }

            // Upsert (o buscar e inyectar) 
            // Para simplificar, insertamos si no existe el nombre, o actualizamos si existe.
            const { data: exist } = await supabase.from('items_menu').select('id, imagen_url').eq('nombre', plato.nombre).maybeSingle()

            const payload = {
                nombre: plato.nombre,
                descripcion: plato.descripcion,
                precio: plato.precio,
                categoria_id: plato.categoria_id,
                activo: true, // Queda visible de inmediato
                agotado_manual: false, // Stock listo
                stock: null, // Asumimos infinito por ahora
                ...(imagen_url && { imagen_url }) // Si subimos imagen, actualiza
            }

            if (exist) {
                // Actualizar
                await supabase.from('items_menu').update(payload).eq('id', exist.id)
            } else {
                // Crear
                await supabase.from('items_menu').insert(payload)
            }
        }

        revalidatePath("/admin/menu")
        revalidatePath("/")
        return { success: true }

    } catch (e: any) {
        console.error(e)
        return { error: e.message || "Error desconocido" }
    }
}

