        pedido.detalle_pedidos.map(d => ({
            id: d.id || "",
            cantidad: d.cantidad,
            precio_unitario: d.precio_unitario,
            nombre: d.items_menu?.nombre || "Item",
        }))
    )

    const cambiarEstado = (nuevoEstado: EstadoPedido) => {
        startTransition(async () => {
            const result = await actualizarEstadoPedido(pedido.id, nuevoEstado)
            if (result?.error) {
                toast.error("Error al actualizar", { description: result.error })
            } else {
                toast.success(`Pedido #${String(pedido.numero_pedido).padStart(5, "0")} ÔåÆ ${LABELS[nuevoEstado]}`)
            }
        })
    }

    const guardarCambios = () => {
        startTransition(async () => {
            // 1. Guardar cambios de items
            for (const item of editItems) {
                if (!item.id) continue
                const original = pedido.detalle_pedidos.find(d => d.id === item.id)
                if (original && (original.cantidad !== item.cantidad || original.precio_unitario !== item.precio_unitario)) {
                    const result = await editarItemPedido(item.id, pedido.id, {
                        cantidad: item.cantidad,
                        precio_unitario: item.precio_unitario
                    })
                    if (result?.error) {
                        toast.error("Error editando item", { description: result.error })
                        return
                    }
                }
            }

            // 2. Guardar notas/direcci├│n si cambiaron
            if (editNotas !== (pedido.notas || "") || editDireccion !== (pedido.direccion_entrega || "")) {
                const result = await editarPedido(pedido.id, {
                    notas: editNotas,
                    direccion_entrega: editDireccion
                })
                if (result?.error) {
                    toast.error("Error editando pedido", { description: result.error })
                    return
                }
            }

            toast.success("┬íCambios guardados, cari├▒o!")
            setIsEditing(false)
        })
    }

    const handleEliminar = () => {
        startTransition(async () => {
            const result = await eliminarPedido(pedido.id)
            if (result?.error) {
                toast.error("Error al cancelar", { description: result.error })
            } else {
                toast.success("Pedido cancelado")
                setShowDeleteConfirm(false)
            }
        })
    }

    const updateItemCantidad = (idx: number, val: number) => {
        setEditItems(prev => prev.map((item, i) => i === idx ? { ...item, cantidad: Math.max(1, val) } : item))
    }

    const updateItemPrecio = (idx: number, val: number) => {
        setEditItems(prev => prev.map((item, i) => i === idx ? { ...item, precio_unitario: Math.max(0, val) } : item))
    }

    return (
        <div className="bg-admin-surface rounded-2xl border border-white/5 overflow-hidden">
            {/* Cabecera del pedido */}
            <div
                className="p-4 sm:p-5 flex flex-wrap items-center gap-3 cursor-pointer hover:bg-white/5 transition-colors"
                onClick={() => setOpen(!open)}
            >
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1 flex-wrap">
                        <span className="font-bold text-white">
                            #{String(pedido.numero_pedido).padStart(5, "0")}
                        </span>
                        <span className="text-xs text-gray-400">
                            {new Date(pedido.created_at).toLocaleString("es-CL", { timeZone: 'America/Santiago', hour: "2-digit", minute: "2-digit" })}
                        </span>
                        <span className="text-xs bg-white/10 text-gray-300 px-2 py-0.5 rounded-full font-medium">
                            {pedido.tipo_entrega === "delivery" ? "­ƒøÁ Delivery" : "­ƒÅ¬ Retiro"}
                        </span>
                        {pedido.hora_solicitada && (
                            <span className="text-xs bg-brand-500/20 text-brand-400 px-2 py-0.5 rounded-full font-bold border border-brand-500/20">
                                ÔÅ░ Para las {pedido.hora_solicitada}
                            </span>
                        )}
                    </div>
                    <p className="text-sm text-gray-300 font-medium truncate">{pedido.cliente_nombre}</p>
                    {pedido.direccion_entrega && (
                        <p className="text-xs font-semibold text-gray-500 truncate mt-0.5">­ƒôì <span className="text-gray-300">{pedido.direccion_entrega}</span></p>
                    )}
                </div>

                <div className="flex items-center gap-3 sm:gap-4">
                    <span className="font-bold text-lg text-white">${pedido.total.toLocaleString("es-CL")}</span>
                    <StatusBadge status={pedido.estado as any} />
                    <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${open ? "rotate-180" : ""}`} />
                </div>
            </div>

            {/* Detalle expandible */}
            {open && (
                <div className="border-t border-white/5 p-4 sm:p-5 space-y-4 animate-in fade-in slide-in-from-top-2">
                    {/* Toolbar de edici├│n */}
                    <div className="flex items-center justify-between">
                        <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider">Items del Pedido</h4>
                        <div className="flex items-center gap-2">
                            {!isEditing ? (
                                <button
                                    onClick={() => setIsEditing(true)}
                                    className="flex items-center gap-1.5 text-xs font-bold text-brand-400 hover:text-brand-300 bg-brand-500/10 hover:bg-brand-500/20 px-3 py-1.5 rounded-lg transition-all border border-brand-500/20"
                                >
                                    <Pencil className="w-3.5 h-3.5" /> Editar
                                </button>
                            ) : (
                                <>
                                    <button
                                        onClick={guardarCambios}
                                        disabled={isPending}
                                        className="flex items-center gap-1.5 text-xs font-bold text-emerald-400 bg-emerald-500/10 hover:bg-emerald-500/20 px-3 py-1.5 rounded-lg transition-all border border-emerald-500/20 disabled:opacity-50"
                                    >
                                        <Save className="w-3.5 h-3.5" /> {isPending ? "Guardando..." : "Guardar"}
                                    </button>
                                    <button
                                        onClick={() => {
                                            setIsEditing(false)
                                            setEditNotas(pedido.notas || "")
                                            setEditDireccion(pedido.direccion_entrega || "")
                                            setEditItems(pedido.detalle_pedidos.map(d => ({
                                                id: d.id || "", cantidad: d.cantidad,
                                                precio_unitario: d.precio_unitario, nombre: d.items_menu?.nombre || "Item"
                                            })))
                                        }}
                                        className="flex items-center gap-1.5 text-xs font-bold text-gray-400 bg-white/5 hover:bg-white/10 px-3 py-1.5 rounded-lg transition-all"
                                    >
                                        <X className="w-3.5 h-3.5" /> Cancelar
                                    </button>
                                </>
                            )}
                        </div>
                    </div>

                    {/* Items */}
                    <ul className="space-y-2">
                        {editItems.map((d, i) => (
                            <li key={i} className="flex items-center justify-between text-sm gap-2">
                                {isEditing ? (
                                    <>
                                        <div className="flex items-center gap-2 flex-1">
                                            <input
                                                type="number"
                                                min={1}
                                                value={d.cantidad}
                                                onChange={(e) => updateItemCantidad(i, parseInt(e.target.value) || 1)}
                                                className="w-14 bg-white/10 border border-white/10 text-white px-2 py-1 rounded-lg text-center text-xs font-bold"
                                            />
                                            <span className="text-gray-300">├ù {d.nombre}</span>
                                        </div>
                                        <div className="flex items-center gap-1">
                                            <span className="text-gray-500 text-xs">$</span>
                                            <input
                                                type="number"
                                                min={0}
                                                value={d.precio_unitario}
                                                onChange={(e) => updateItemPrecio(i, parseInt(e.target.value) || 0)}
                                                className="w-20 bg-white/10 border border-white/10 text-white px-2 py-1 rounded-lg text-right text-xs font-bold"
                                            />
                                        </div>
                                        <span className="text-gray-400 text-xs w-20 text-right font-bold">
                                            = ${(d.cantidad * d.precio_unitario).toLocaleString("es-CL")}
                                        </span>
                                    </>
                                ) : (
                                    <>
                                        <span className="text-gray-300">{d.cantidad}x {d.nombre}</span>
                                        <span className="text-gray-400">${(d.precio_unitario * d.cantidad).toLocaleString("es-CL")}</span>
                                    </>
                                )}
                            </li>
                        ))}
                    </ul>

                    {/* Notas y Direcci├│n editables */}
                    {isEditing ? (
                        <div className="space-y-3 pt-2">
                            <div>
                                <label className="text-xs font-bold text-gray-400 uppercase tracking-wider block mb-1">Notas</label>
                                <textarea
                                    value={editNotas}
                                    onChange={(e) => setEditNotas(e.target.value)}
                                    rows={2}
                                    className="w-full bg-white/10 border border-white/10 text-white px-3 py-2 rounded-xl text-sm placeholder:text-gray-600 resize-none"
                                    placeholder="Sin notas..."
                                />
                            </div>
                            {pedido.tipo_entrega === "delivery" && (
                                <div>
                                    <label className="text-xs font-bold text-gray-400 uppercase tracking-wider block mb-1">Direcci├│n</label>
                                    <input
                                        type="text"
                                        value={editDireccion}
                                        onChange={(e) => setEditDireccion(e.target.value)}
                                        className="w-full bg-white/10 border border-white/10 text-white px-3 py-2 rounded-xl text-sm"
                                    />
                                </div>
                            )}
                        </div>
                    ) : (
                        pedido.notas && (
                            <div className="bg-amber-500/10 rounded-xl p-3 text-sm text-amber-300 border border-amber-500/20">
                                <span className="font-bold">Nota:</span> {pedido.notas}
                            </div>
                        )
                    )}

                    {/* Cambiar estado */}
                    <div>
                        <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-3">Cambiar Estado</h4>
                        <div className="flex flex-wrap gap-2">
                            {ESTADOS.filter(e => e !== pedido.estado).map((estado) => (
                                <button
                                    key={estado}
                                    disabled={isPending}
                                    onClick={() => cambiarEstado(estado)}
                                    className="text-xs font-semibold px-3 py-1.5 rounded-lg border border-white/10 text-gray-300 hover:border-brand-500 hover:text-brand-400 transition-colors disabled:opacity-50"
                                >
                                    ÔåÆ {LABELS[estado]}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Eliminar pedido */}
                    <div className="pt-2 border-t border-white/5">
                        {!showDeleteConfirm ? (
                            <button
                                onClick={() => setShowDeleteConfirm(true)}
                                className="flex items-center gap-1.5 text-xs font-bold text-red-400 hover:text-red-300 bg-red-500/10 hover:bg-red-500/20 px-3 py-1.5 rounded-lg transition-all border border-red-500/20"
                            >
                                <Trash2 className="w-3.5 h-3.5" /> Cancelar Pedido
                            </button>
                        ) : (
                            <div className="flex items-center gap-3">
                                <span className="text-xs text-red-400 font-bold">┬┐Segura que quer├¡s cancelar este pedido?</span>
                                <button
                                    onClick={handleEliminar}
                                    disabled={isPending}
                                    className="text-xs font-bold text-white bg-red-600 hover:bg-red-700 px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50"
                                >
                                    {isPending ? "Cancelando..." : "S├¡, cancelar"}
                                </button>
                                <button
                                    onClick={() => setShowDeleteConfirm(false)}
                                    className="text-xs font-bold text-gray-400 hover:text-gray-300"
                                >
                                    No, volver
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    )
}

import { createClient } from "@/lib/supabase/server"
import { redirect } from "next/navigation"
import { PedidoRow } from "./PedidoRow"

export default async function AdminPedidosPage() {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect("/login")

    // Cargar TODOS los pedidos ACTIVOS/Pendientes sin importar la fecha,
    // y cargar los completados/cancelados del DIA DE HOY para mantener historial relevante.
    const hoy = new Date().toISOString().split("T")[0]

    const { data: pedidos } = await supabase
        .from("pedidos")
        .select(`
      id, numero_pedido, estado, total, tipo_entrega, 
      direccion_entrega, hora_solicitada, notas, created_at,
      profiles!pedidos_cliente_id_fkey(nombre, telefono),
      items_pedido(
        id, cantidad, precio_unitario, subtotal,
        items_menu(nombre)
      )
    `)
        // Trae los pendientes siempre, O trae los de hoy sin importar su estado
        .or(`estado.in.(pendiente_pago,pago_en_revision,confirmado,en_preparacion,en_delivery),created_at.gte.${hoy}T00:00:00`)
        .order("created_at", { ascending: false })
        .limit(100) // L├¡mite de seguridad

    // Formatear los datos para el componente
    const pedidosFormateados = (pedidos || []).map(p => ({
        id: p.id,
        numero_pedido: p.numero_pedido,
        estado: p.estado,
        total: p.total,
        tipo_entrega: p.tipo_entrega,
        direccion_entrega: p.direccion_entrega,
        hora_solicitada: p.hora_solicitada,
        notas: p.notas,
        created_at: p.created_at,
        cliente_nombre: (p.profiles as any)?.nombre || "Cliente",
        cliente_telefono: (p.profiles as any)?.telefono || null,
        detalle_pedidos: (p.items_pedido || []) as any,
    }))

    const byEstado = {
        activos: pedidosFormateados.filter(p => ["pendiente_pago", "pago_en_revision", "confirmado", "en_preparacion", "en_delivery"].includes(p.estado)),
        completados: pedidosFormateados.filter(p => ["entregado", "cancelado"].includes(p.estado)),
    }

    // Calcular Consolidador de Deudores Semanales
    const deudoresMap = byEstado.activos
        .filter(p => p.estado === "pendiente_pago")
        .reduce((acc, p) => {
            const tel = p.cliente_telefono
            if (!tel) return acc
            if (!acc[tel]) {
                acc[tel] = { nombre: p.cliente_nombre, telefono: tel, total: 0, count: 0 }
            }
            acc[tel].total += p.total
            acc[tel].count += 1
            return acc
        }, {} as Record<string, { nombre: string; telefono: string; total: number; count: number }>)

    const deudores = Object.values(deudoresMap)

    return (
        <div className="space-y-8">
            <div>
                <h1 className="text-3xl font-heading font-bold text-white">Pedidos del D├¡a</h1>
                <p className="text-gray-400 mt-1">{pedidosFormateados.length} pediditos registrados hoy</p>
            </div>

            {pedidosFormateados.length === 0 ? (
                <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-16 text-center">
                    <p className="text-gray-400 text-lg">A├║n no hay pedidos para hoy.</p>
                </div>
            ) : (
                <div className="space-y-10">

                    {/* Consolidado de Deudas */}
                    {deudores.length > 0 && (
                        <section className="bg-red-50 p-6 rounded-3xl border border-red-100 shadow-sm">
                            <h2 className="text-sm font-bold text-red-600 uppercase tracking-wider mb-4 flex items-center gap-2">
                                <span className="w-2 h-2 bg-red-600 rounded-full animate-pulse inline-block" />
                                Pendientes de Cobro (Agrupados por Cliente)
                            </h2>
                            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
                                {deudores.map((deudor, idx) => {
                                    const msj = `┬íHola, ${deudor.nombre}! ­ƒæ®ÔÇì­ƒì│ La T├¡a Elvira por aqu├¡. Tienes un total de ${deudor.count} ${deudor.count > 1 ? 'pedidos pendientes' : 'pedido pendiente'} de pago en tu libreta por un total de $${deudor.total.toLocaleString("es-CL")}. ┬íCuando puedas te das el tiempo, mi ni├▒@! Un abrazo grande.`
                                    const waLink = `https://wa.me/${deudor.telefono.replace('+', '')}?text=${encodeURIComponent(msj)}`

                                    return (
                                        <div key={idx} className="bg-white p-4 rounded-2xl border border-red-100 flex flex-col justify-between">
                                            <div>
                                                <p className="font-bold text-gray-900">{deudor.nombre}</p>
                                                <p className="text-xs text-gray-500 mb-2">{deudor.count} pedido(s)</p>
                                            </div>
                                            <div className="flex items-center justify-between mt-2">
                                                <span className="font-black text-red-600 text-lg">${deudor.total.toLocaleString('es-CL')}</span>
                                                <a href={waLink} target="_blank" rel="noopener noreferrer" className="bg-green-500 hover:bg-green-600 text-white px-3 py-1.5 rounded-lg text-xs font-bold transition-colors">
                                                    Cobrar v├¡a WA
                                                </a>
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        </section>
                    )}

                    {/* Activos */}
                    {byEstado.activos.length > 0 && (
                        <section>
                            <h2 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                                <span className="w-2 h-2 bg-amber-400 rounded-full animate-pulse inline-block" />
                                Activos ({byEstado.activos.length})
                            </h2>
                            <div className="space-y-3">
                                {byEstado.activos.map(p => <PedidoRow key={p.id} pedido={p} />)}
                            </div>
                        </section>
                    )}

                    {/* Completados */}
                    {byEstado.completados.length > 0 && (
                        <section>
                            <h2 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                                <span className="w-2 h-2 bg-gray-300 rounded-full inline-block" />
                                Completados ({byEstado.completados.length})
                            </h2>
                            <div className="space-y-3 opacity-70">
                                {byEstado.completados.map(p => <PedidoRow key={p.id} pedido={p} />)}
                            </div>
                        </section>
                    )}
                </div>
            )}
        </div>
    )
}

import { createClient } from "@/lib/supabase/server"
import { redirect } from "next/navigation"
import { UsuariosTable } from "./UsuariosTable"

export const revalidate = 0

export default async function AdminUsuariosPage() {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect("/login")

    // Cargar usuarios con resumen de pedidos
    const { data: usuarios } = await supabase
        .from("profiles")
        .select("id, nombre, email, rol, telefono, created_at, activo, limite_fiado, avatar_url")
        .order("activo", { ascending: false })
        .order("created_at", { ascending: false })

    // Cargar pedidos agrupados por cliente
    const { data: pedidos } = await supabase
        .from("pedidos")
        .select("id, numero_pedido, total, estado, created_at, cliente_id, tipo_entrega, items_pedido(cantidad, items_menu(nombre))")
        .order("created_at", { ascending: false })

    // Mapear pedidos por cliente
    const pedidosPorCliente: Record<string, any[]> = {}
    const deudasPorCliente: Record<string, number> = {}
    const totalGastadoPorCliente: Record<string, number> = {}

    pedidos?.forEach(p => {
        const cid = p.cliente_id
        if (!pedidosPorCliente[cid]) pedidosPorCliente[cid] = []
        pedidosPorCliente[cid].push(p)

        // Total gastado (solo pagados/entregados)
        if (!totalGastadoPorCliente[cid]) totalGastadoPorCliente[cid] = 0
        if (p.estado !== 'cancelado') totalGastadoPorCliente[cid] += (p.total || 0)

        // Deuda fiados
        if (!deudasPorCliente[cid]) deudasPorCliente[cid] = 0
        if (p.estado === 'pendiente_pago') deudasPorCliente[cid] += (p.total || 0)
    })

    const usuariosConDatos = (usuarios || []).map(u => ({
        ...u,
        totalGastado: totalGastadoPorCliente[u.id] || 0,
        deuda: deudasPorCliente[u.id] || 0,
        totalPedidos: pedidosPorCliente[u.id]?.length || 0,
        ultimosPedidos: (pedidosPorCliente[u.id] || []).slice(0, 5).map((p: any) => ({
            id: p.id,
            numero_pedido: p.numero_pedido,
            total: p.total,
            estado: p.estado,
            created_at: p.created_at,
            tipo_entrega: p.tipo_entrega,
            items: (p.items_pedido || []).map((i: any) => `${i.cantidad}x ${i.items_menu?.nombre || 'Plato'}`).join(', ')
        }))
    }))

    return <UsuariosTable usuarios={usuariosConDatos} selfId={user.id} />
}

"use server"

import { createClient } from "@/lib/supabase/server"
import { redirect } from "next/navigation"
import { MercadoPagoConfig, Preference } from "mercadopago"

// Configurar cliente MercadoPago con el Access Token
const mpClient = new MercadoPagoConfig({ accessToken: process.env.MP_ACCESS_TOKEN || '' })

export async function processOrder(formData: FormData, cartItems: { id: string, precio: number, cantidad: number, nombre?: string }[]) {
    const supabase = await createClient()

    // 1. Validar el usuario
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        throw new Error("No autorizado")
    }

    // 2. Extraer datos del formulario
    const tipoEntrega = formData.get("tipoEntrega") as "retiro" | "delivery"
    const metodoPago = formData.get("metodoPago") as "transferencia" | "mercadopago" | "efectivo"
    const direccion = formData.get("direccion") as string
    const notas = formData.get("notas") as string
    const horaSolicitada = formData.get("hora_solicitada") as string
    const direccionEntrega = formData.get("direccion_entrega") as string

    // Validaci├│n b├ísica
    if (tipoEntrega === 'delivery' && !direccionEntrega) {
        return { error: 'Debes proporcionar una direcci├│n de entrega' }
    }

    if (metodoPago === 'mercadopago' && !process.env.MP_ACCESS_TOKEN) {
        return { error: 'Mercado Pago no est├í configurado en el servidor.' }
    }

    // 2.5 Validaci├│n de Stock en BD
    const itemIds = cartItems.map(item => item.id)
    const { data: dbItems, error: itemsError } = await supabase
        .from('items_menu')
        .select('id, nombre, stock, agotado_manual, activo')
        .in('id', itemIds)

    if (itemsError || !dbItems) {
        return { error: 'Error al verificar disponibilidad del men├║.' }
    }

    for (const cartItem of cartItems) {
        const dbItem = dbItems.find(i => i.id === cartItem.id)
        if (!dbItem) {
            return { error: `El producto ${cartItem.nombre || 'solicitado'} ya no existe.` }
        }
        if (!dbItem.activo || dbItem.agotado_manual) {
            return { error: `El producto ${dbItem.nombre} se ha agotado reci├®n.` }
        }
        if (dbItem.stock !== null && cartItem.cantidad > dbItem.stock) {
            return { error: `Solo quedan ${dbItem.stock} unidades de ${dbItem.nombre}.` }
        }
    }

    // 3. Totales (Server Side)
    const subtotal = cartItems.reduce((acc, item) => acc + (item.precio * item.cantidad), 0)

    // Obtener Costo Delivery global desde BD
    let configDeliveryVal = 1500;
    const { data: conf } = await supabase.from('configuraciones').select('valor').eq('clave', 'costo_delivery').single()
    if (conf?.valor) {
        configDeliveryVal = parseInt(conf.valor)
    }

    const costoDelivery = tipoEntrega === 'delivery' ? configDeliveryVal : 0
    const total = subtotal + costoDelivery

    // 4. Inserci├│n DB
    const { data: nuevoPedido, error: pedidoError } = await supabase
        .from('pedidos')
        .insert({
            cliente_id: user.id,
            estado: 'pendiente_pago',
            fecha_pedido: new Date().toISOString().split('T')[0],
            tipo_entrega: tipoEntrega,
            direccion_entrega: direccionEntrega || null,
            metodo_pago: metodoPago,
            notas: notas || null,
            hora_solicitada: horaSolicitada || null,
            subtotal,
            costo_delivery: costoDelivery,
            total,
        })
        .select()
        .single()

    if (pedidoError || !nuevoPedido) {
        console.error("Error al crear pedido", pedidoError)
        return { error: 'Error al procesar pedido. Intenta nuevamente.' }
    }

    // Detalle
    const detalleRows = cartItems.map(item => ({
        pedido_id: nuevoPedido.id,
        item_menu_id: item.id,
        nombre_item: item.nombre || 'Colaci├│n',
        cantidad: item.cantidad,
        precio_unitario: item.precio,
        subtotal: item.precio * item.cantidad
    }))
    const { error: detalleError } = await supabase.from('items_pedido').insert(detalleRows)

    if (detalleError) {
        console.error("Error detalle", detalleError)
        // Eliminar el pedido principal para evitar hu├®rfanos sin dependencias
        await supabase.from('pedidos').delete().eq('id', nuevoPedido.id)
        return { error: 'Error parcial guardando ├¡tems. Intenta nuevamente.' }
    }

    // 4.5 Deducci├│n de Stock
    for (const cartItem of cartItems) {
        const dbItem = dbItems.find(i => i.id === cartItem.id)
        if (dbItem && dbItem.stock !== null) {
            const nuevoStock = Math.max(0, dbItem.stock - cartItem.cantidad)
            await supabase.from('items_menu').update({ stock: nuevoStock }).eq('id', cartItem.id)
        }
    }

    // 5. MANEJAR MERCADO PAGO O TRANSFERENCIA
    if (metodoPago === 'mercadopago') {
        try {
            const preference = new Preference(mpClient)

            // Construir Items para MercadoPago
            const mpItems = cartItems.map(item => ({
                id: item.id,
                title: item.nombre || 'Colaci├│n',
                quantity: item.cantidad,
                unit_price: item.precio,
                currency_id: 'CLP'
            }))

            // Agregar el costo de env├¡o como un item extra
            if (costoDelivery > 0) {
                mpItems.push({
                    id: 'DELIVERY',
                    title: 'Costo de Env├¡o',
                    quantity: 1,
                    unit_price: costoDelivery,
                    currency_id: 'CLP'
                })
            }

            // Crear la Preferencia
            // ATENCI├ôN: En prod, localhost debe cambiar a la URL real ej. https://micolacion.cl
            const base_url = process.env.NEXT_PUBLIC_SITE_URL || 'http://localhost:3000'
            const response = await preference.create({
                body: {
                    items: mpItems,
                    metadata: {
                        pedido_id: nuevoPedido.id
                    },
                    back_urls: {
                        success: `${base_url}/checkout/success?id=${nuevoPedido.id}&status=mp_success`,
                        failure: `${base_url}/carrito?estado=fallo_pago`,
                        pending: `${base_url}/checkout/success?id=${nuevoPedido.id}&status=mp_pending`
                    },
                    auto_return: "approved",
                }
            })

            // Retornamos la URL al cliente para que el navegador lo redirija a MercadoPago
            return { rawUrl: response.init_point! }

        } catch (err) {
            console.error(err)
            return { error: 'Error al iniciar Mercado Pago. Revisa el Token.' }
        }
    }

    // SI ES TRANSFERENCIA (Default action)
    redirect(`/checkout/success?id=${nuevoPedido.id}`)
}

"use client"

import { useState, useTransition, useEffect } from "react"
import { useRouter } from "next/navigation"
import { useCartStore } from "@/store/cartStore"
import { Button } from "@/components/ui/Button"
import { ArrowLeft, CheckCircle2, ChevronRight, MapPin, Store, CreditCard, Clock, BookOpen } from "lucide-react"
import Link from "next/link"
import { processOrder } from "./actions"
import { toast } from "sonner"
import Image from "next/image"
import { createClient } from "@/lib/supabase/client"

export default function CheckoutPage() {
    const router = useRouter()
    const { items, getTotal, clearCart } = useCartStore()
    const [isPending, startTransition] = useTransition()
    const supabase = createClient()

    const [sysConfig, setSysConfig] = useState({ costoDelivery: 1500, limiteFiado: 3, deudas: 0, loading: true })

    const [tipoEntrega, setTipoEntrega] = useState<"delivery" | "retiro">("delivery")
    const subtotal = getTotal()
    const costoDelivery = tipoEntrega === "delivery" ? sysConfig.costoDelivery : 0
    const total = subtotal + costoDelivery

    // Estado para capturar direcci├│n, hora solicitada y notas
    const [direccion, setDireccion] = useState<string>("")
    const [horaSolicitada, setHoraSolicitada] = useState<string>("")
    const [notas, setNotas] = useState<string>("")

    // Evita entrar al checkout con el carrito vac├¡o
    useEffect(() => {
        if (items.length === 0) {
            router.push("/carrito")
        }
    }, [items.length, router])

    // Cargar configuraciones de Delivery y Fiado
    useEffect(() => {
        async function loadConfig() {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) return

            // Costo global delivery
            const { data: conf } = await supabase.from('configuraciones').select('valor').eq('clave', 'costo_delivery').single()

            // Perfil para el l├¡mite de fiado individual
            const { data: prof } = await supabase.from('profiles').select('limite_fiado').eq('id', user.id).single()

            // Conteo de deudas activas (pedidos sin pagar)
            const { count: deudas } = await supabase.from('pedidos')
                .select('*', { count: 'exact', head: true })
                .eq('cliente_id', user.id)
                .in('estado', ['pendiente_pago', 'pago_en_revision'])

            setSysConfig({
                costoDelivery: conf?.valor ? parseInt(conf.valor) : 1500,
                limiteFiado: prof?.limite_fiado ?? 3,
                deudas: deudas || 0,
                loading: false
            })
        }
        loadConfig()
    }, [supabase])

    // Modales de confirmaci├│n
    const [showConfirmModal, setShowConfirmModal] = useState(false)
    const [formDataToSubmit, setFormDataToSubmit] = useState<FormData | null>(null)

    const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault()
        const formData = new FormData(e.currentTarget)

        // Validaci├│n de hora
        if (!horaSolicitada) {
            toast.error("Por favor ind├¡canos a qu├® hora deseas tu pedido.")
            return
        }

        // Validaci├│n de direcci├│n en delivery
        if (tipoEntrega === 'delivery' && !direccion.trim()) {
            toast.error("Para Delivery, debes indicar una direcci├│n de entrega v├ílida.")
            return
        }

        // Anexar los metadatos din├ímicos del carrito local a la acci├│n
        const cartItems = items.map(item => ({
            id: item.id,
            precio: item.precio,
            cantidad: item.cantidad
        }))

        // Anexar los nuevos campos al formData
        formData.append('hora_solicitada', horaSolicitada)
        formData.append('direccion_entrega', direccion)
        formData.append('notas', notas)


        setFormDataToSubmit(formData)
        setShowConfirmModal(true)
    }

    const ejecutarCheckoutReal = () => {
        if (!formDataToSubmit) return
        startTransition(async () => {
            const cartItems = items.map(item => ({ id: item.id, precio: item.precio, cantidad: item.cantidad }))
            const result = await processOrder(formDataToSubmit, cartItems)

            if (result?.error) {
                toast.error("Error al procesar", { description: result.error })
                setShowConfirmModal(false)
            } else if (result?.rawUrl) {
                if (typeof window !== "undefined") {
                    window.location.href = result.rawUrl
                }
                clearCart()
            } else {
                clearCart() // Server action redirige
            }
        })
    }

    if (items.length === 0 || sysConfig.loading) return <div className="min-h-screen bg-gray-50 animate-pulse pb-32" />

    const puedeFiar = sysConfig.deudas < sysConfig.limiteFiado

    return (
        <div className="min-h-screen bg-gray-50 pb-32">
            <header className="relative border-b border-white/20 px-4 py-8 sm:py-10 flex items-center shadow-xl overflow-hidden -mt-1">
                <div className="absolute inset-0 z-0">
                    <Image
                        src="/images/prep-bg.png"
                        alt="Preparando tu pedido casero"
                        fill
                        className="object-cover object-center"
                        priority
                    />
                    <div className="absolute inset-0 bg-gradient-to-r from-black/60 to-black/30 backdrop-blur-[1px]" />
                </div>
                <div className="relative z-10 w-full max-w-3xl mx-auto flex items-center">
                    <Link href="/carrito" className="text-white/90 hover:text-white transition flex items-center gap-2 drop-shadow-md bg-black/20 px-3 py-1.5 rounded-full backdrop-blur-md border border-white/10">
                        <ArrowLeft className="w-5 h-5" />
                        <span className="font-semibold text-sm">Volver</span>
                    </Link>
                    <div className="flex-1 text-center">
                        <h1 className="text-2xl sm:text-3xl font-heading font-bold text-white absolute left-1/2 -translate-x-1/2 drop-shadow-lg shadow-black tracking-wide">
                            Finalizar Pedido
                        </h1>
                    </div>
                </div>
            </header>

            <main className="max-w-3xl mx-auto px-4 py-6">
                <form onSubmit={handleSubmit} className="space-y-8">

                    {/* 1. Tipo de Entrega */}
                    <section className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
                        <h2 className="text-lg font-bold font-heading text-gray-900 mb-4">1. Entrega</h2>
                        <div className="grid grid-cols-2 gap-4">
                            <label
                                className={`relative flex flex-col items-center gap-2 p-4 rounded-xl border-2 cursor-pointer transition-all ${tipoEntrega === 'delivery' ? 'border-brand-500 bg-brand-50/50' : 'border-gray-100 hover:border-gray-200 bg-white'}`}
                            >
                                <input type="radio" name="tipoEntrega" value="delivery" className="sr-only" checked={tipoEntrega === 'delivery'} onChange={() => setTipoEntrega('delivery')} />
                                <MapPin className={`w-8 h-8 ${tipoEntrega === 'delivery' ? 'text-brand-500' : 'text-gray-400'}`} />
                                <span className={`font-semibold text-sm ${tipoEntrega === 'delivery' ? 'text-brand-700' : 'text-gray-600'}`}>Delivery</span>
                                {tipoEntrega === 'delivery' && <CheckCircle2 className="w-5 h-5 text-brand-500 absolute top-2 right-2" />}
                            </label>

                            <label
                                className={`relative flex flex-col items-center gap-2 p-4 rounded-xl border-2 cursor-pointer transition-all ${tipoEntrega === 'retiro' ? 'border-brand-500 bg-brand-50/50' : 'border-gray-100 hover:border-gray-200 bg-white'}`}
                            >
                                <input type="radio" name="tipoEntrega" value="retiro" className="sr-only" checked={tipoEntrega === 'retiro'} onChange={() => setTipoEntrega('retiro')} />
                                <Store className={`w-8 h-8 ${tipoEntrega === 'retiro' ? 'text-brand-500' : 'text-gray-400'}`} />
                                <span className={`font-semibold text-sm ${tipoEntrega === 'retiro' ? 'text-brand-700' : 'text-gray-600'}`}>Retiro en local</span>
                                {tipoEntrega === 'retiro' && <CheckCircle2 className="w-5 h-5 text-brand-500 absolute top-2 right-2" />}
                            </label>
                        </div>

                        {/* Input de Hora Solicitada */}
                        <div className="mt-6 space-y-3 animate-in fade-in slide-in-from-top-2">
                            <label className="block text-sm font-semibold text-gray-700">┬┐A qu├® hora deseas tu pedido? <span className="text-red-500">*</span></label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                    <Clock className="w-5 h-5 text-gray-400" />
                                </div>
                                <select
                                    value={horaSolicitada}
                                    onChange={(e) => setHoraSolicitada(e.target.value)}
                                    required
                                    className="w-full pl-11 pr-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-transparent transition-all appearance-none bg-white"
                                >
                                    <option value="" disabled>Selecciona un horario disponible</option>
                                    <option value="12:00">12:00 hrs</option>
                                    <option value="12:30">12:30 hrs</option>
                                    <option value="13:00">13:00 hrs</option>
                                    <option value="13:30">13:30 hrs</option>
                                    <option value="14:00">14:00 hrs</option>
                                    <option value="14:30">14:30 hrs</option>
                                </select>
                                <div className="absolute inset-y-0 right-0 pr-4 flex items-center pointer-events-none">
                                    <ChevronRight className="w-4 h-4 text-gray-400 rotate-90" />
                                </div>
                            </div>
                            <p className="text-xs text-gray-500 mt-2 ml-1">Para organizar nuestro tiempo, ind├¡canos a qu├® hora vienes o te lo enviamos.</p>
                        </div>

                        {tipoEntrega === 'delivery' && (
                            <div className="mt-6 space-y-3 animate-in fade-in slide-in-from-top-2">
                                <label className="block text-sm font-semibold text-gray-700">Tu direcci├│n de entrega <span className="text-red-500">*</span></label>
                                <input
                                    type="text"
                                    name="direccion"
                                    required
                                    value={direccion}
                                    onChange={(e) => setDireccion(e.target.value)}
                                    placeholder="Ej: Oficina central, 3er piso"
                                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-transparent transition-all"
                                />
                            </div>
                        )}

                        {/* Notas movidas a Entrega */}
                        <div className="mt-6 animate-in fade-in slide-in-from-top-2">
                            <label className="block text-sm font-semibold text-gray-700 mb-2">Notas para el local (opcional)</label>
                            <textarea
                                name="notas"
                                value={notas}
                                onChange={(e) => setNotas(e.target.value)}
                                rows={2}
                                placeholder="Ej: Sin sal, tenedor por favor..."
                                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-500 resize-none transition-all"
                            />
                        </div>
                    </section>

                    {/* 2. Pago */}
                    <section className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
                        <h2 className="text-lg font-bold font-heading text-gray-900 mb-4">2. M├®todo de Pago</h2>
                        <div className="space-y-4">

                            {/* Mercado Pago */}
                            <label className="flex items-center gap-3 p-4 border border-blue-500 bg-blue-50/50 rounded-xl cursor-pointer hover:bg-blue-50 transition-colors">
                                <input type="radio" name="metodoPago" value="mercadopago" defaultChecked className="w-4 h-4 text-brand-500" />
                                <div className="w-8 h-8 bg-[#009EE3] rounded-full flex items-center justify-center flex-shrink-0">
                                    <CreditCard className="w-4 h-4 text-white" />
                                </div>
                                <div className="flex-1">
                                    <span className="block font-bold text-gray-900">Tarjeta o Mercado Pago</span>
                                    <span className="block text-xs text-gray-500">Ser├ís redirigido de forma segura para pagar.</span>
                                </div>
                            </label>

                            {/* Anotar en Libreta / Fiado */}
                            {puedeFiar ? (
                                <label className="flex items-center gap-3 p-4 border border-brand-200 bg-brand-50/20 rounded-xl cursor-pointer hover:bg-brand-50 transition-colors relative overflow-hidden">
                                    <input type="radio" name="metodoPago" value="transferencia" className="w-4 h-4 text-brand-500" />
                                    <div className="w-8 h-8 bg-brand-100 rounded-full flex items-center justify-center flex-shrink-0">
                                        <BookOpen className="w-4 h-4 text-brand-600" />
                                    </div>
                                    <div className="flex-1">
                                        <span className="block font-bold text-brand-800">Anotar en la Libreta</span>
                                        <span className="block text-xs text-brand-600/80">Tu l├¡mite de confianza: {sysConfig.limiteFiado - sysConfig.deudas} pedidos disponibles.</span>
                                    </div>
                                </label>
                            ) : (
                                <div className="flex items-center gap-3 p-4 border border-red-100 bg-red-50/50 rounded-xl opacity-75">
                                    <div className="w-8 h-8 bg-red-100 rounded-full flex items-center justify-center flex-shrink-0">
                                        <BookOpen className="w-4 h-4 text-red-500 opacity-50" />
                                    </div>
                                    <div className="flex-1">
                                        <span className="block font-bold text-gray-500 line-through decoration-red-500/50">Anotar en la Libreta</span>
                                        <span className="block text-xs text-red-600">Alcanzaste tu l├¡mite de pedidos pendientes de pago ({sysConfig.deudas}/{sysConfig.limiteFiado}).</span>
                                    </div>
                                </div>
                            )}

                        </div>
                    </section>

                    {/* Resumen Final */}
                    <section className="bg-gray-100/50 rounded-2xl p-6">
                        <div className="space-y-3 text-sm text-gray-600 mb-4">
                            <div className="flex justify-between">
                                <span>Subtotal ({items.reduce((acc, i) => acc + i.cantidad, 0)} items)</span>
                                <span>${subtotal.toLocaleString("es-CL")}</span>
                            </div>
                            {tipoEntrega === 'delivery' && (
                                <div className="flex justify-between text-brand-600">
                                    <span>Costo de Delivery</span>
                                    <span>+${costoDelivery.toLocaleString("es-CL")}</span>
                                </div>
                            )}
                        </div>
                        <div className="border-t border-gray-200 pt-4 flex justify-between items-center">
                            <span className="text-lg font-bold text-gray-900">Total</span>
                            <span className="text-2xl font-bold font-heading text-brand-600">
                                ${total.toLocaleString("es-CL")}
                            </span>
                        </div>
                    </section>

                    {/* Floater CTA */}
                    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 sm:p-6 shadow-[0_-10px_40px_rgba(0,0,0,0.05)] z-40">
                        <div className="max-w-3xl mx-auto">
                            <Button type="submit" variant="primary" disabled={isPending || items.length === 0} className="w-full py-4 text-lg font-bold shadow-brand-500/25">
                                {isPending ? "Procesando..." : "Confirmar Pedido"}
                                {!isPending && <ChevronRight className="w-5 h-5 ml-1" />}
                            </Button>
                        </div>
                    </div>
                </form>
            </main>

            {/* Modal de Confirmaci├│n de Compra Local */}
            {showConfirmModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center px-4 bg-gray-900/60 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-white rounded-3xl w-full max-w-sm overflow-hidden shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                        <div className="p-6 text-center">
                            <div className="w-16 h-16 bg-brand-100 text-brand-600 rounded-full flex items-center justify-center mx-auto mb-4">
                                <CheckCircle2 className="w-8 h-8" />
                            </div>
                            <h3 className="text-xl font-bold font-heading text-gray-900 mb-2">
                                ┬┐Gusto confirmado?
                            </h3>
                            <p className="text-sm text-gray-600 mb-6 font-medium">
                                Revisamos todo. El valor total de tu orden es de <span className="font-bold text-gray-900">${total.toLocaleString('es-CL')}</span>.
                                ┬┐Listo para enviarlo al Mes├│n de T├¡a Elvira?
                            </p>
                            <div className="flex flex-col gap-3">
                                <Button
                                    variant="primary"
                                    onClick={ejecutarCheckoutReal}
                                    disabled={isPending}
                                    className="w-full py-3.5 text-base font-bold shadow-md"
                                >
                                    {isPending ? 'Ev├¡ando...' : 'S├¡, confirmar y Pagar'}
                                </Button>
                                <button
                                    onClick={() => setShowConfirmModal(false)}
                                    disabled={isPending}
                                    className="w-full py-3 text-sm font-semibold text-gray-500 hover:text-gray-900 transition-colors"
                                >
                                    No, volver a revisar
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div >
    )
}

import { createClient } from "@/lib/supabase/server"
import { redirect } from "next/navigation"
import Link from "next/link"
import { Button } from "@/components/ui/Button"
import Image from "next/image"
import { CheckCircle, MessageCircle, ChefHat } from "lucide-react"

export default async function CheckoutSuccessPage({
    searchParams,
}: {
    searchParams: Promise<{ id?: string, status?: string, payment_id?: string }>
}) {
    const { id, status } = await searchParams

    if (!id) redirect("/")

    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect("/login")

    // Obtener el pedido para validar que pertenece al usuario
    const { data: pedido } = await supabase
        .from("pedidos")
        .select("*, items_pedido(*, items_menu(nombre))")
        .eq("id", id)
        .single()

    if (!pedido || pedido.cliente_id !== user.id) {
        redirect("/")
    }

    // Actualizar estado si viene desde MercadoPago con ├®xito, usando la funci├│n segura (Bypass RLS)
    if ((status === 'approved' || status === 'mp_success') && pedido.estado === 'pendiente_pago') {
        const { error: updateError } = await supabase.rpc('confirmar_pago_mp', { pedido_id: id })

        if (!updateError) {
            pedido.estado = 'en_preparacion'
        } else {
            console.error("Error seteando estado a pagado:", updateError)
        }
    }

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col pt-12">
            <main className="flex-1 max-w-lg w-full mx-auto px-4 pb-20 relative z-10">
                <div className="bg-white rounded-3xl shadow-2xl border border-gray-100 p-8 text-center animate-in zoom-in-95 duration-500 overflow-hidden relative">

                    {/* Header Image Background inside card */}
                    <div className="absolute top-0 left-0 right-0 h-40 z-0">
                        <Image
                            src="/images/prep-bg.png"
                            alt="Preparando comida"
                            fill
                            className="object-cover opacity-90"
                            priority
                        />
                        <div className="absolute inset-0 bg-gradient-to-b from-black/50 to-white backdrop-blur-[1px]" />
                    </div>

                    <div className="relative z-10 w-24 h-24 bg-white rounded-full flex items-center justify-center mx-auto mb-6 shadow-xl border-4 border-emerald-50 mt-12">
                        {pedido.estado === 'en_preparacion' ? (
                            <ChefHat className="w-12 h-12 text-brand-500 animate-bounce" />
                        ) : (
                            <CheckCircle className="w-12 h-12 text-emerald-500" />
                        )}
                    </div>

                    <h1 className="relative z-10 text-2xl font-heading font-bold text-gray-900 mb-2">
                        {pedido.estado === 'en_preparacion' ? '┬íPago recibido, cari├▒o!' : '┬íYa tengo tu pedido, cari├▒o!'}
                    </h1>
                    <p className="relative z-10 text-gray-600 mb-6 font-medium">
                        {pedido.estado === 'en_preparacion'
                            ? 'Al tiro me pongo a preparar tu platito con todo el cari├▒o del mundo.'
                            : 'Ya anot├® tu pedidito en mi libreta, cari├▒o. Queda pendientito no m├ís.'}
                        <br /><span className="font-bold text-brand-600 text-lg">Tu n├║mero es el #{String(pedido.numero_pedido).padStart(5, '0')}</span>
                    </p>

                    {/* Instrucciones de Pago */}
                    {pedido.metodo_pago === 'transferencia' && (() => {
                        // Construir el mensaje de WhatsApp
                        const itemsTxt = (pedido.items_pedido || []).map((d: any) => `Ôû¬´©Å ${d.cantidad}x ${d.items_menu?.nombre || 'Item'}`).join('%0A')

                        // Formatear direcci├│n
                        let direccionTxt = ""
                        if (pedido.tipo_entrega === "retiro") {
                            direccionTxt = "­ƒÅó Retiro en Local"
                        } else {
                            direccionTxt = `­ƒôì Delivery a: ${pedido.direccion_entrega || 'Sin direcci├│n'}`
                        }

                        // Agregar notas si hay
                        if (pedido.notas) {
                            direccionTxt += ` (Nota: ${pedido.notas})`
                        }

                        const mensajeWhatsApp = `┬íHola! Env├¡o el comprobante de mi pedido #${String(pedido.numero_pedido).padStart(5, '0')} ­ƒº¥%0A%0A*DATOS DEL CLIENTE*%0A­ƒæñ ${user.user_metadata?.full_name || 'Cliente'}%0A${direccionTxt}%0A%0A*RESUMEN DEL PEDIDO*%0A${itemsTxt}%0A----------------------%0A­ƒÆ░ *TOTAL PAGADO: $${pedido.total.toLocaleString("es-CL")}*%0A%0AAdjunto mi comprobante de transferencia. ┬íGracias!`;
                        const urlWhatsApp = `https://wa.me/56972508272?text=${mensajeWhatsApp}`;

                        return (
                            <div className="bg-brand-50 rounded-2xl p-6 text-left mb-6 border border-brand-100">
                                <h3 className="font-bold text-brand-900 mb-2">Para confirmar tu pedido:</h3>
                                <p className="text-sm text-brand-800 mb-4">
                                    Transfiere el total exacto a la siguiente cuenta y env├¡anos el comprobante por WhatsApp.
                                </p>

                                <div className="space-y-2 text-sm bg-white p-4 rounded-xl shadow-sm mb-4 border border-brand-100">
                                    <div className="flex justify-between items-center">
                                        <span className="text-gray-500">Banco:</span>
                                        <span className="font-medium text-gray-900">Banco Estado</span>
                                    </div>
                                    <div className="flex justify-between items-center">
                                        <span className="text-gray-500">Tipo:</span>
                                        <span className="font-medium text-gray-900">Cuenta RUT</span>
                                    </div>
                                    <div className="flex justify-between items-center">
                                        <span className="text-gray-500">RUT:</span>
                                        <span className="font-medium text-gray-900">12.345.678-9</span>
                                    </div>
                                    <div className="flex justify-between items-center">
                                        <span className="text-gray-500">Monto:</span>
                                        <span className="font-bold text-brand-600 text-lg">${pedido.total.toLocaleString("es-CL")}</span>
                                    </div>
                                </div>

                                <a
                                    href={urlWhatsApp}
                                    target="_blank"
                                    rel="noreferrer"
                                    className="w-full flex items-center justify-center gap-2 bg-[#25D366] hover:bg-[#1DA851] text-white py-3 rounded-xl font-bold transition-colors shadow-sm"
                                >
                                    <MessageCircle className="w-5 h-5" /> Enviar Comprobante
                                </a>
                            </div>
                        )
                    })()}

                    <div className="space-y-3">
                        <Link href="/mis-pedidos" className="block w-full text-center py-3 text-sm font-semibold text-gray-600 bg-gray-100 hover:bg-gray-200 rounded-xl transition-colors">
                            Ir a ver mis pedidos
                        </Link>
                        <Link href="/" className="block w-full text-center py-3 text-sm font-medium text-brand-600 hover:text-brand-700 transition-colors">
                            Volver al Inicio
                        </Link>
                    </div>
                </div>
            </main>
        </div>
    )
}

"use client"

import { useTransition } from "react"
import { MapPin, Phone, MessageCircle, Clock, CheckCircle2, ChevronRight, Navigation } from "lucide-react"
import { marcarEnCamino, marcarEntregado } from "./actions"
import { toast } from "sonner"
import { format } from "date-fns"
import { es } from "date-fns/locale"

interface Pedido {
    id: string
    numero_pedido: number
    estado: string
    tipo_entrega: string
    direccion_envio: string | null
    telefono_contacto: string | null
    notas: string | null
    total: number
    created_at: string
}

export function PedidoDeliveryCard({ pedido }: { pedido: Pedido }) {
    const [isPending, startTransition] = useTransition()

    // Acci├│n dependiendo del estado
    const handleAction = () => {
        startTransition(async () => {
            let res;
            if (pedido.estado === "en_preparacion") {
                res = await marcarEnCamino(pedido.id)
            } else if (pedido.estado === "en_delivery") {
                res = await marcarEntregado(pedido.id)
            }

            if (res?.error) {
                toast.error("Error al actualizar", { description: res.error })
            } else {
                toast.success(
                    pedido.estado === "en_preparacion"
                        ? "Pedido marcado como EN CAMINO"
                        : "Pedido marcado como ENTREGADO"
                )
            }
        })
    }

    const isPreparando = pedido.estado === "en_preparacion"

    // Limpiar el tel├®fono para el link de WhatsApp (quitar +, espacios)
    const cleanPhone = pedido.telefono_contacto?.replace(/[^0-9]/g, "") || ""

    return (
        <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden mb-4">
            {/* Cabecera Tarjeta */}
            <div className={`px-5 py-4 border-b ${isPreparando ? 'bg-amber-50/50 border-amber-100/50' : 'bg-brand-50/50 border-brand-100/50'} flex items-center justify-between`}>
                <div>
                    <span className="font-heading font-bold text-gray-900 text-lg">
                        #{String(pedido.numero_pedido).padStart(5, "0")}
                    </span>
                    <p className="text-xs text-gray-500 font-medium mt-0.5">
                        {format(new Date(pedido.created_at), "HH:mm", { locale: es })}
                    </p>
                </div>
                <div>
                    <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold leading-none
            ${isPreparando ? 'bg-amber-100 text-amber-700' : 'bg-brand-100 text-brand-700'}`}>
                        {isPreparando ? (
                            <><Clock className="w-3.5 h-3.5" /> Recoger</>
                        ) : (
                            <><Navigation className="w-3.5 h-3.5" /> En Tr├ínsito</>
                        )}
                    </span>
                </div>
            </div>

            {/* Cuerpo Tarjeta */}
            <div className="p-5 space-y-4">

                {/* Direcci├│n */}
                <div className="flex items-start gap-3">
                    <div className="p-2 bg-gray-50 rounded-xl mt-0.5">
                        <MapPin className="w-5 h-5 text-gray-400" />
                    </div>
                    <div>
                        <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-0.5">Direcci├│n de Entrega</p>
                        <p className="font-semibold text-gray-900 leading-snug">
                            {pedido.tipo_entrega === "retiro"
                                ? "Retiro en Local"
                                : (pedido.direccion_envio || "Sin direcci├│n especificada")}
                        </p>
                    </div>
                </div>

                {/* Contacto */}
                <div className="flex items-start gap-3">
                    <div className="p-2 bg-gray-50 rounded-xl mt-0.5">
                        <UserIcon className="w-5 h-5 text-gray-400" />
                    </div>
                    <div className="flex-1">
                        <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-0.5">Contacto</p>
                        <p className="font-semibold text-gray-900 leading-snug">
                            {pedido.telefono_contacto || "Sin tel├®fono"}
                        </p>
                    </div>
                    {pedido.telefono_contacto && (
                        <div className="flex gap-2">
                            <a
                                href={`tel:${pedido.telefono_contacto}`}
                                className="p-2.5 bg-gray-100 text-gray-600 rounded-full hover:bg-gray-200 transition-colors"
                            >
                                <Phone className="w-4 h-4" />
                            </a>
                            <a
                                href={`https://wa.me/${cleanPhone}`}
                                target="_blank"
                                rel="noreferrer"
                                className="p-2.5 bg-green-50 text-green-600 rounded-full hover:bg-green-100 transition-colors"
                            >
                                <MessageCircle className="w-4 h-4" />
                            </a>
                        </div>
                    )}
                </div>

                {/* Notas (si hay) */}
                {pedido.notas && (
                    <div className="bg-amber-50 rounded-2xl p-4 text-sm text-amber-800">
                        <span className="font-bold flex items-center gap-1.5 mb-1">
                            <MessageCircle className="w-4 h-4" /> Nota del Cliente:
                        </span>
                        <p className="leading-relaxed">{pedido.notas}</p>
                    </div>
                )}

            </div>

            {/* Bot├│n de Acci├│n Principal */}
            <div className="p-5 pt-0">
                <button
                    onClick={handleAction}
                    disabled={isPending}
                    className={`w-full py-4 rounded-2xl font-bold text-sm flex items-center justify-center gap-2 transition-all active:scale-[0.98] ${isPending
                        ? "bg-gray-100 text-gray-400 cursor-not-allowed"
                        : isPreparando
                            ? "bg-gray-900 text-white hover:bg-gray-800 shadow-xl shadow-gray-200"
                            : "bg-brand-500 text-white hover:bg-brand-600 shadow-xl shadow-brand-200"
                        }`}
                >
                    {isPending ? (
                        "Actualizando..."
                    ) : isPreparando ? (
                        <><Navigation className="w-5 h-5" /> Iniciar Ruta de Entrega</>
                    ) : (
                        <><CheckCircle2 className="w-5 h-5" /> Confirmar Entrega</>
                    )}
                </button>
            </div>

        </div>
    )
}

function UserIcon(props: any) {
    return (
        <svg
            {...props}
            xmlns="http://www.w3.org/2000/svg"
            width="24"
            height="24"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        >
            <path d="M19 21v-2a4 4 0 0 0-4-4H9a4 4 0 0 0-4 4v2" />
            <circle cx="12" cy="7" r="4" />
        </svg>
    )
}

"use client"

import { useState, useTransition } from "react"
import { actualizarPerfilUsuario } from "./actions"
import { toast } from "sonner"
import { createClient } from "@/lib/supabase/client"
import { Save, User, MapPin, Phone, ShieldCheck, User as UserIcon, Camera } from "lucide-react"

export function PerfilForm({
    profile,
    userEmail,
    isAdmin,
    isRepartidor
}: {
    profile: any,
    userEmail: string | undefined,
    isAdmin: boolean,
    isRepartidor: boolean
}) {
    const [isPending, startTransition] = useTransition()
    const [isEditing, setIsEditing] = useState(false)

    // Extraemos el +569 si ya viene en el perfil para mostrar solo los 8 d├¡gitos
    const savedPhone = profile?.telefono || ""
    const initialPhone = savedPhone.startsWith("+569") ? savedPhone.slice(4) : savedPhone

    // Valores locales
    const [nombre, setNombre] = useState(profile?.nombre || "")
    const [telefono, setTelefono] = useState(initialPhone)
    const [direccion, setDireccion] = useState(profile?.direccion || "")
    const [avatarUrl, setAvatarUrl] = useState<string | null>(profile?.avatar_url || null)
    const [isUploading, setIsUploading] = useState(false)

    const supabase = createClient()

    const handleAvatarUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
        try {
            setIsUploading(true)
            if (!event.target.files || event.target.files.length === 0) {
                throw new Error('Debes seleccionar una imagen.')
            }

            const file = event.target.files[0]
            const fileExt = file.name.split('.').pop()
            const filePath = `${profile.id}-${Math.random()}.${fileExt}`

            const { error: uploadError } = await supabase.storage
                .from('avatars')
                .upload(filePath, file)

            if (uploadError) {
                throw uploadError
            }

            const { data } = supabase.storage.from('avatars').getPublicUrl(filePath)
            setAvatarUrl(data.publicUrl)
            toast.success("┬íListo, cari├▒o! Foto subida. Ahora dale a Guardar Cambios.")
        } catch (error: any) {
            toast.error("Error al subir imagen", { description: error.message })
        } finally {
            setIsUploading(false)
        }
    }

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault()

        const formData = new FormData()
        formData.append("nombre", nombre)
        formData.append("telefono", telefono ? `+569${telefono.trim()}` : "")
        formData.append("direccion", direccion)
        if (avatarUrl) {
            formData.append("avatar_url", avatarUrl)
        }

        startTransition(async () => {
            const result = await actualizarPerfilUsuario(formData)
            if (result.error) {
                toast.error("Error al guardar perfil", { description: result.error })
            } else {
                toast.success("┬íListo, qued├│ guard├í tu info, cari├▒o!")
                setIsEditing(false)
            }
        })
    }

    return (
        <form onSubmit={handleSave} className="space-y-6">

            {/* Cabecera Interactiva de Identidad (Avatar + Roles + Email) */}
            <div className="flex flex-col sm:flex-row gap-6 sm:items-center mb-8 pb-8 border-b border-wood-100">
                <div className="relative group shrink-0">
                    <div className="w-20 h-20 rounded-full bg-brand-50 flex items-center justify-center text-brand-600 font-bold text-3xl shrink-0 overflow-hidden border border-brand-100">
                        {avatarUrl ? (
                            <img src={avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
                        ) : (
                            profile?.nombre?.charAt(0).toUpperCase() || "?"
                        )}
                    </div>

                    {/* Bot├│n de edici├│n de avatar */}
                    {isEditing && (
                        <label className="absolute inset-0 bg-black/40 rounded-full flex flex-col items-center justify-center text-white cursor-pointer opacity-0 group-hover:opacity-100 transition-opacity">
                            <Camera className="w-6 h-6 mb-1" />
                            <span className="text-[10px] font-bold uppercase tracking-wider">
                                {isUploading ? 'Subiendo...' : 'Cambiar'}
                            </span>
                            <input
                                type="file"
                                className="hidden"
                                accept="image/*"
                                onChange={handleAvatarUpload}
                                disabled={isUploading}
                            />
                        </label>
                    )}
                </div>

                <div className="space-y-1.5 flex-1 p-2">
                    <h2 className="text-xl font-bold text-wood-900">{profile?.nombre || "Sin nombre"}</h2>

                    {/* Correo visible en readonly */}
                    <div className="mt-2 mb-4 max-w-sm">
                        <label className="text-xs font-bold text-wood-400 uppercase tracking-wider">Correo Vinculado</label>
                        <input
                            type="email"
                            disabled
                            value={userEmail || ""}
                            className="w-full mt-1 bg-gray-50/50 border border-gray-100 text-gray-500 px-3 py-2 rounded-xl text-sm font-medium outline-none"
                        />
                    </div>

                    {/* Badges de Roles */}
                    <div className="flex flex-wrap gap-2 pt-2">
                        <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold bg-gray-100 text-gray-700">
                            <UserIcon className="w-3.5 h-3.5" /> Cliente
                        </span>
                        {isAdmin && (
                            <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold bg-purple-100 text-purple-700">
                                <ShieldCheck className="w-3.5 h-3.5" /> Administrador
                            </span>
                        )}
                        {isRepartidor && (
                            <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold bg-blue-100 text-blue-700">
                                <ShieldCheck className="w-3.5 h-3.5" /> Repartidor
                            </span>
                        )}
                    </div>
                </div>
            </div>

            <div className="grid sm:grid-cols-2 gap-6">

                {/* Nombre */}
                <div className="space-y-2">
                    <label className="flex items-center gap-2 text-wood-500 text-sm font-medium ml-1">
                        <User className="w-4 h-4" />
                        Nombre Completo
                    </label>
                    <input
                        type="text"
                        required
                        disabled={!isEditing}
                        value={nombre}
                        onChange={e => setNombre(e.target.value)}
                        className="w-full px-4 py-3 bg-wood-50/50 rounded-xl border border-wood-100 disabled:opacity-75 disabled:bg-gray-50 focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none transition-all placeholder:text-wood-400 font-medium text-wood-900"
                    />
                </div>

                {/* Tel├®fono */}
                <div className="space-y-2">
                    <label className="flex items-center gap-2 text-wood-500 text-sm font-medium ml-1">
                        <Phone className="w-4 h-4" />
                        Celular
                    </label>
                    <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                            <span className="text-wood-500 font-medium">+56 9</span>
                        </div>
                        <input
                            type="tel"
                            disabled={!isEditing}
                            value={telefono}
                            onChange={e => setTelefono(e.target.value)}
                            maxLength={8}
                            pattern="[0-9]{8}"
                            title="Ingresa 8 d├¡gitos num├®ricos v├ílidos"
                            placeholder="1234 5678"
                            className="w-full pl-16 pr-4 py-3 bg-wood-50/50 rounded-xl border border-wood-100 disabled:opacity-75 disabled:bg-gray-50 focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none transition-all placeholder:text-wood-400 font-medium text-wood-900"
                        />
                    </div>
                </div>

                {/* Direcci├│n Completa (100% ancho) */}
                <div className="sm:col-span-2 space-y-2">
                    <label className="flex items-center gap-2 text-wood-500 text-sm font-medium ml-1">
                        <MapPin className="w-4 h-4" />
                        Direcci├│n para Despacho Frecuente
                    </label>
                    <input
                        type="text"
                        disabled={!isEditing}
                        value={direccion}
                        onChange={e => setDireccion(e.target.value)}
                        placeholder="Ej: Arauco 234, Oficina 4..."
                        className="w-full px-4 py-3 bg-wood-50/50 rounded-xl border border-wood-100 disabled:opacity-75 disabled:bg-gray-50 focus:ring-2 focus:ring-brand-500 focus:border-brand-500 outline-none transition-all placeholder:text-wood-400 font-medium text-wood-900"
                    />
                </div>
            </div>

            {/* Controles */}
            <div className="pt-4 flex items-center justify-end gap-3 border-t border-wood-100 mt-6">
                {!isEditing ? (
                    <button
                        type="button"
                        onClick={() => setIsEditing(true)}
                        className="bg-brand-50 text-brand-700 font-bold px-6 py-2.5 rounded-xl hover:bg-brand-100 transition-colors"
                    >
                        Editar Datos
                    </button>
                ) : (
                    <>
                        <button
                            type="button"
                            onClick={() => {
                                setIsEditing(false)
                                // Revertir campos
                                setNombre(profile?.nombre || "")
                                setTelefono(initialPhone)
                                setDireccion(profile?.direccion || "")
                                setAvatarUrl(profile?.avatar_url || null)
                            }}
                            disabled={isPending}
                            className="bg-gray-50 text-gray-600 font-bold px-5 py-2.5 rounded-xl hover:bg-gray-100 transition-colors disabled:opacity-50"
                        >
                            Cancelar
                        </button>
                        <button
                            type="submit"
                            disabled={isPending}
                            className="flex items-center gap-2 bg-brand-500 text-white font-bold px-6 py-2.5 rounded-xl hover:bg-brand-600 shadow-md shadow-brand-500/20 transition-all disabled:opacity-50"
                        >
                            <Save className="w-4 h-4" />
                            {isPending ? "Guardando..." : "Guardar Cambios"}
                        </button>
                    </>
                )}
            </div>
        </form>
    )
}
